import React, { useState } from 'react';

export default function EnlacesPropriosForm() {
  const [form, setForm] = useState({
    campo1: '',
    campo2: '',
    campo3: ''
  });

  const handleChange = e => {
    setForm({ ...form, [e.target.name]: e.target.value });
  };

  const handleSubmit = e => {
    e.preventDefault();
    alert('Dados enviados!');
  };

  return (
    <div style={{
      background: '#fff',
      borderRadius: '16px',
      minHeight: '120px',
      boxShadow: '0 2px 8px #0001',
      padding: '2.5rem 2rem 2rem 2rem',
      margin: '2rem auto',
      maxWidth: 600,
      display: 'flex',
      flexDirection: 'column',
      alignItems: 'center',
      justifyContent: 'center',
    }}>
      <div style={{fontSize:'1.2rem',color:'#1976d2',fontWeight:700,marginBottom:8}}>Enlaces Próprios</div>
      <form onSubmit={handleSubmit} style={{width:'100%',maxWidth:400,display:'flex',flexDirection:'column',gap:16}}>
        <input name="campo1" value={form.campo1} onChange={handleChange} placeholder="Campo 1" required />
        <input name="campo2" value={form.campo2} onChange={handleChange} placeholder="Campo 2" required />
        <input name="campo3" value={form.campo3} onChange={handleChange} placeholder="Campo 3" required />
        <button type="submit" style={{background:'#1976d2',color:'#fff',border:'none',borderRadius:'6px',padding:'0.5rem 2rem',fontWeight:'bold',fontSize:'1rem',cursor:'pointer',marginTop:16}}>Salvar</button>
      </form>
    </div>
  );
}
